# All sequences of length 2 with elements < 3
# Median is floor((2+1)/2) = 1st smallest value
sequences = []
for a in range(3):
    for b in range(3):
        sequences.append([a, b])

def is_good(seq, m):
    cnt = {}
    for x in seq:
        cnt[x] = cnt.get(x, 0) + 1
    for i in range(m):
        for j in range(i+1, m):
            if i in cnt and j in cnt:
                if cnt[i] > cnt[j]:
                    return False
    return True

def median(seq):
    n = len(seq)
    sorted_seq = sorted(seq)
    return sorted_seq[(n+1)//2 - 1]

xor_sum = 0
for seq in sequences:
    if is_good(seq, 3):
        med = median(seq)
        print(f'{seq} -> median={med}')
        xor_sum ^= med
